frame_eqs:
db = .5*db + .5* bass_att;
bb = bb + .1 *db ;
dt = .5*dt + .5* treb_att;
tt = tt+ .1 * dt ;
dm = .5*dm + .5* mid_att;
mm = mm+ .1 * dm ;

q1 = tt;
q2 = bb;
q3 = mm;

pixel_eqs:
vx = 0.5+cos(time*0.2)*1;
vy = 0.5+sin(time*0.2)*1;
vz = 0;
z = 0 - vz;
x = x - vx;
y = y - vy;

d = time*0.1+.05*(q1+q2+q3);
xx = sin(d)*x + cos(d)*y;
yy = cos(d)*x - sin(d)*y;

x = xx;
y = yy;


x = x + mx +.01*(q1-q2);
y = y + my +.01*(q2-q1);
z = z + vz + .01*(q3/time);
cx = 0;
cy = 0;
cz = 0.5+treb*0.0;
vx = 0;
vy = 0;
vz = 0;
zoom = 0.33;
w = 1/zoom*(1+sqrt(sqr(z-cz) + sqr(x-cx)+sqr(y-cy)));
dx = -(x-mx)*w;// + w*(y-my);
dy = -(y-my)*w ;// - w*(x-mx);
